#include<bits/stdc++.h>
using namespace std;
const int N=5e6;
long long mod;
long long jc[N+10],siz[N+10],f[N+10],ny[N+10],n;
long long fastpow(long long x,long long y)
{
    long long sum=1;
    while(y)
    {
        if(y%2==1)
        {
            sum=sum*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return sum;
}
long long C(long long n,long long m)
{
    return jc[n]*ny[m]%mod*ny[n-m]%mod;
}
long long Lucas(long long n,long long m)
{
    if(m==0)
    {
        return 1;
    }
    return C(n%mod,m%mod)*Lucas(n/mod,m/mod)%mod;
}
void dfs(int x)
{
    siz[x]=1;
    f[x]=1;
    if(x*2>n)
    {
        return;
    }
    dfs(x*2);
    siz[x]+=siz[x*2];
    if(x*2+1<=n)
    {
        dfs(x*2+1);
        siz[x]+=siz[x*2+1];
    }
    f[x]=f[x*2]*Lucas(siz[x]-1,siz[x*2])%mod;
    if(x*2+1<=n)
    {
        f[x]*=f[x*2+1];
        f[x]%=mod;
    }
}
int main()
{
    scanf("%lld%lld",&n,&mod);
    jc[0]=1;
    for(int i=1;i<=min(n,mod-1);i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    ny[min(n,mod-1)]=fastpow(jc[min(n,mod-1)],mod-2);
    for(int i=min(n,mod-1)-1;i>=0;i--)
    {
        ny[i]=ny[i+1]*(i+1)%mod;
    }
    dfs(1);
    printf("%lld",f[1]);
    return 0;
}
